/**
 * WebSocket Manager - WebSocket handling
 */

import { WebSocket, WebSocketServer } from 'ws'
import { Server } from 'http'
import { log } from './utils'
import { PendingFile } from './types'

export interface WebSocketManagerDeps {
  getToken: () => string
  getPtyManager: () => any
  getPort: () => number
  getTerminalSubscriptions: () => Map<string, Set<WebSocket>>
  getPtyStreams: () => Map<string, Set<WebSocket>>
  getPtyDataBuffer: () => Map<string, string[]>
  getConnectedClients: () => Set<WebSocket>
  getPendingFiles: () => Map<string, PendingFile>
}

export function setupWebSocket(server: Server, deps: WebSocketManagerDeps): WebSocketServer {
  const wss = new WebSocketServer({ noServer: true })

  // Handle upgrade requests manually to support multiple paths
  server.on('upgrade', (req, socket, head) => {
    const url = new URL(req.url || '', `http://localhost:${deps.getPort()}`)
    const pathname = url.pathname

    // Get token from Sec-WebSocket-Protocol header (preferred) or query string (fallback)
    const protocolHeader = req.headers['sec-websocket-protocol'] as string | undefined
    const protocols = protocolHeader?.split(',').map(p => p.trim()) || []
    const tokenFromProtocol = protocols.find(p => p.startsWith('token-'))?.slice(6)
    const tokenFromQuery = url.searchParams.get('token')
    const token = tokenFromProtocol || tokenFromQuery

    log('WebSocket upgrade request', {
      url: req.url,
      pathname,
      hasProtocolToken: !!tokenFromProtocol,
      hasQueryToken: !!tokenFromQuery,
      headers: {
        host: req.headers.host,
        origin: req.headers.origin,
        upgrade: req.headers.upgrade
      }
    })

    // Validate token for all WebSocket connections
    if (token !== deps.getToken()) {
      log('WebSocket auth failed', { providedToken: token?.slice(0, 8) })
      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n')
      socket.destroy()
      return
    }

    // Handle PTY stream WebSocket: /api/pty/:id/stream
    const ptyStreamMatch = pathname.match(/^\/api\/pty\/([^/]+)\/stream$/)
    if (ptyStreamMatch) {
      const ptyId = ptyStreamMatch[1]
      handlePtyStreamUpgrade(req, socket, head, ptyId, deps)
      return
    }

    // Handle main WebSocket path: /ws
    if (pathname === '/ws') {
      wss.handleUpgrade(req, socket, head, (ws) => {
        wss.emit('connection', ws, req)
      })
      return
    }

    // Unknown WebSocket path
    log('Unknown WebSocket path', { pathname })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
  })

  wss.on('connection', (ws: WebSocket, _req) => {
    log('WebSocket client connected (main)')

    deps.getConnectedClients().add(ws)

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())
        handleWebSocketMessage(ws, msg, deps)
      } catch (e) {
        log('Invalid WebSocket message', { error: String(e) })
      }
    })

    ws.on('close', () => {
      deps.getConnectedClients().delete(ws)

      deps.getTerminalSubscriptions().forEach((subscribers, ptyId) => {
        subscribers.delete(ws)
        if (subscribers.size === 0) {
          deps.getTerminalSubscriptions().delete(ptyId)
        }
      })
      log('WebSocket client disconnected (main)')
    })

    // Send welcome message
    ws.send(JSON.stringify({ type: 'connected', timestamp: Date.now() }))

    // Send any pending files to new client
    sendPendingFilesToClient(ws, deps.getPendingFiles())
  })

  return wss
}

function handlePtyStreamUpgrade(
  req: any,
  socket: any,
  head: any,
  ptyId: string,
  deps: WebSocketManagerDeps
): void {
  const ptyManager = deps.getPtyManager()
  if (!ptyManager || !ptyManager.getProcess(ptyId)) {
    log('PTY stream upgrade failed - PTY not found', { ptyId })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
    return
  }

  const streamWss = new WebSocketServer({ noServer: true })

  streamWss.handleUpgrade(req, socket, head, (ws) => {
    log('PTY stream connected', { ptyId })

    const ptyStreams = deps.getPtyStreams()
    if (!ptyStreams.has(ptyId)) {
      ptyStreams.set(ptyId, new Set())
    }
    ptyStreams.get(ptyId)!.add(ws)

    ws.send(JSON.stringify({ type: 'connected', ptyId }))

    // Flush any buffered data
    flushPtyBuffer(ptyId, ws, deps.getPtyDataBuffer())

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())

        switch (msg.type) {
          case 'input':
            if (msg.data && ptyManager) {
              ptyManager.write(ptyId, msg.data)
            }
            break

          case 'resize':
            if (msg.cols && msg.rows && ptyManager) {
              ptyManager.resize(ptyId, msg.cols, msg.rows)
            }
            break

          case 'ping':
            ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
            break

          default:
            log('Unknown PTY stream message type', { type: msg.type, ptyId })
        }
      } catch (e) {
        log('Invalid PTY stream message', { error: String(e), ptyId })
      }
    })

    ws.on('close', () => {
      log('PTY stream disconnected', { ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
      if (ptyStreams.get(ptyId)?.size === 0) {
        ptyStreams.delete(ptyId)
      }
    })

    ws.on('error', (err) => {
      log('PTY stream error', { error: String(err), ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
    })
  })
}

function handleWebSocketMessage(ws: WebSocket, msg: any, deps: WebSocketManagerDeps): void {
  const ptyManager = deps.getPtyManager()
  const terminalSubscriptions = deps.getTerminalSubscriptions()

  switch (msg.type) {
    case 'subscribe':
      if (msg.ptyId) {
        if (!terminalSubscriptions.has(msg.ptyId)) {
          terminalSubscriptions.set(msg.ptyId, new Set())
        }
        terminalSubscriptions.get(msg.ptyId)!.add(ws)
        ws.send(JSON.stringify({ type: 'subscribed', ptyId: msg.ptyId }))
      }
      break

    case 'unsubscribe':
      if (msg.ptyId) {
        terminalSubscriptions.get(msg.ptyId)?.delete(ws)
      }
      break

    case 'write':
      if (msg.ptyId && msg.data && ptyManager) {
        ptyManager.write(msg.ptyId, msg.data)
      }
      break

    case 'resize':
      if (msg.ptyId && msg.cols && msg.rows && ptyManager) {
        ptyManager.resize(msg.ptyId, msg.cols, msg.rows)
      }
      break

    case 'ping':
      ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
      break
  }
}

function flushPtyBuffer(ptyId: string, ws: WebSocket, ptyDataBuffer: Map<string, string[]>): void {
  const buffer = ptyDataBuffer.get(ptyId)
  if (!buffer || buffer.length === 0) return

  buffer.forEach(data => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type: 'data', data }))
    }
  })

  ptyDataBuffer.delete(ptyId)
}

function sendPendingFilesToClient(ws: WebSocket, pendingFiles: Map<string, PendingFile>): void {
  const now = Date.now()
  // Clean up expired files first
  for (const [fileId, file] of pendingFiles) {
    if (file.expiresAt < now) {
      pendingFiles.delete(fileId)
    }
  }

  const files = Array.from(pendingFiles.values()).map(f => ({
    id: f.id,
    name: f.name,
    size: f.size,
    mimeType: f.mimeType,
    message: f.message
  }))

  if (files.length > 0) {
    ws.send(JSON.stringify({ type: 'files:pending', files }))
  }
}

export function broadcastTerminalData(
  ptyId: string,
  data: string,
  terminalSubscriptions: Map<string, Set<WebSocket>>
): void {
  const subscribers = terminalSubscriptions.get(ptyId)
  if (!subscribers) return

  const message = JSON.stringify({
    type: 'terminal-data',
    ptyId,
    data
  })

  subscribers.forEach(ws => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message)
    }
  })
}

export function broadcastPtyData(
  ptyId: string,
  data: string,
  ptyStreams: Map<string, Set<WebSocket>>,
  ptyDataBuffer: Map<string, string[]>
): void {
  const streams = ptyStreams.get(ptyId)

  // If no streams connected, buffer the data
  if (!streams || streams.size === 0) {
    if (!ptyDataBuffer.has(ptyId)) {
      ptyDataBuffer.set(ptyId, [])
    }
    const buffer = ptyDataBuffer.get(ptyId)!
    buffer.push(data)
    // Limit buffer size
    if (buffer.length > 1000) {
      buffer.shift()
    }
    return
  }

  const message = JSON.stringify({
    type: 'data',
    data
  })

  streams.forEach(ws => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message)
    }
  })
}

export function broadcastPtyExit(
  ptyId: string,
  code: number,
  ptyStreams: Map<string, Set<WebSocket>>,
  terminalSubscriptions?: Map<string, Set<WebSocket>>
): void {
  const streams = ptyStreams.get(ptyId)
  if (streams && streams.size > 0) {
    const message = JSON.stringify({
      type: 'exit',
      code
    })

    streams.forEach(ws => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message)
        ws.close(1000, 'PTY exited')
      }
    })
  }

  // Clean up stale subscriptions for this PTY
  ptyStreams.delete(ptyId)
  terminalSubscriptions?.delete(ptyId)
}

import { BrowserWindow, ipcMain } from 'electron'
import { PtyManager } from '../../pty-manager.js'
import { SessionStore } from '../../session-store.js'
import { ApiServerManager } from '../../api-server.js'
import { pendingApiPrompts, autoCloseSessions } from '../api-prompt-handler.js'

function maybeRespondToCursorPositionRequest(
  ptyManager: PtyManager,
  ptyToBackend: Map<string, string>,
  ptyId: string,
  data: string
): void {
  const backend = ptyToBackend.get(ptyId)
  if (!backend || backend === 'claude') return
  if (data.includes('\x1b[6n') || data.includes('\x1b[?6n')) {
    ptyManager.write(ptyId, '\x1b[1;1R')
  }
}

export function registerPtyHandlers(
  ptyManager: PtyManager,
  sessionStore: SessionStore,
  apiServerManager: ApiServerManager,
  ptyToProject: Map<string, string>,
  ptyToBackend: Map<string, string>,
  getMainWindow: () => BrowserWindow | null
): void {
  ipcMain.handle('pty:spawn', (_, { cwd, sessionId, model, backend }: { cwd: string; sessionId?: string; model?: string; backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' }) => {
    try {
      const workspace = sessionStore.getWorkspace()
      const project = workspace.projects.find(p => p.path === cwd)
      const globalSettings = sessionStore.getSettings()

      const normalizedGlobalBackend = globalSettings.backend === 'default'
        ? undefined
        : globalSettings.backend

      const normalizedBackend = backend === 'default' ? undefined : backend
      const effectiveBackend = normalizedBackend
        || (project?.backend && project.backend !== 'default'
          ? project.backend
          : normalizedGlobalBackend || 'claude')

      const pending = pendingApiPrompts.get(cwd)
      const effectiveModel = model || pending?.model
      const autoAcceptTools = project?.autoAcceptTools ?? globalSettings.autoAcceptTools
      const permissionMode = project?.permissionMode ?? globalSettings.permissionMode

      const id = ptyManager.spawn(cwd, sessionId, autoAcceptTools, permissionMode, effectiveModel, effectiveBackend)
      ptyToProject.set(id, cwd)
      ptyToBackend.set(id, effectiveBackend)

      if (project?.apiPort && project.apiAutoStart && !apiServerManager.isRunning(cwd)) {
        apiServerManager.start(cwd, project.apiPort)
      }

      const mainWindow = getMainWindow()

      ptyManager.onData(id, (data) => {
        maybeRespondToCursorPositionRequest(ptyManager, ptyToBackend, id, data)
        try {
          mainWindow?.webContents.send(`pty:data:${id}`, data)
        } catch (e) {
          console.error('IPC send failed', e)
        }
      })

      ptyManager.onExit(id, (code) => {
        try {
          mainWindow?.webContents.send(`pty:exit:${id}`, code)
        } catch (e) {
          console.error('IPC send failed', e)
        }
        ptyToProject.delete(id)
        ptyToBackend.delete(id)
        autoCloseSessions.delete(id)
      })

      if (pending) {
        pendingApiPrompts.delete(cwd)
        if (pending.autoClose) autoCloseSessions.add(id)
        setTimeout(() => {
          // Verify PTY still exists before writing (race condition guard)
          if (ptyManager.getProcess(id)) {
            ptyManager.write(id, pending.prompt + '\n')
            pending.resolve({ success: true, message: 'Prompt sent to new terminal', sessionCreated: true })
          } else {
            pending.resolve({ success: false, error: 'Terminal exited before prompt could be sent' })
          }
        }, 4000)
      }

      return id
    } catch (error: any) {
      // Resolve pending prompt immediately on spawn failure instead of waiting for 30s timeout
      const pending = pendingApiPrompts.get(cwd)
      if (pending) {
        pendingApiPrompts.delete(cwd)
        pending.resolve({ success: false, error: `Failed to start terminal: ${error.message}` })
      }
      console.error('Failed to spawn PTY:', error)
      throw new Error(`Failed to start Claude: ${error.message}`)
    }
  })

  ipcMain.on('pty:write', (_, { id, data }: { id: string; data: string }) => ptyManager.write(id, data))
  ipcMain.on('pty:resize', (_, { id, cols, rows }: { id: string; cols: number; rows: number }) => ptyManager.resize(id, cols, rows))
  ipcMain.on('pty:kill', (_, id: string) => {
    ptyToProject.delete(id)
    ptyToBackend.delete(id)
    ptyManager.kill(id)
  })

  ipcMain.handle('pty:set-backend', async (_, { id: oldId, backend: newBackend }: { id: string; backend: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' }) => {
    const process = ptyManager.getProcess(oldId)
    if (!process) return

    const { cwd, sessionId, backend: oldBackend } = process
    const effectiveSessionId = oldBackend !== newBackend ? undefined : sessionId

    ptyManager.kill(oldId)
    const newId = ptyManager.spawn(cwd, effectiveSessionId, undefined, undefined, undefined, newBackend)

    const projectPath = ptyToProject.get(oldId)
    if (projectPath) {
      ptyToProject.set(newId, projectPath)
      ptyToProject.delete(oldId)
    }
    ptyToBackend.set(newId, newBackend)
    ptyToBackend.delete(oldId)

    const mainWindow = getMainWindow()

    ptyManager.onData(newId, (data) => {
      maybeRespondToCursorPositionRequest(ptyManager, ptyToBackend, newId, data)
      mainWindow?.webContents.send(`pty:data:${newId}`, data)
    })

    ptyManager.onExit(newId, (code) => {
      mainWindow?.webContents.send(`pty:exit:${newId}`, code)
      ptyToProject.delete(newId)
      ptyToBackend.delete(newId)
    })

    mainWindow?.webContents.send('pty:recreated', { oldId, newId, backend: newBackend })
  })
}

/**
 * Authentication Rate Limiting Module
 *
 * Provides rate limiting for failed authentication attempts.
 */

import type { RateLimitEntry } from './types.js'

// Constants
const RATE_LIMIT_MAX_ATTEMPTS = 5
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000 // 15 minutes
const RATE_LIMIT_BLOCK_DURATION_MS = 15 * 60 * 1000 // 15 minutes

const rateLimitStore = new Map<string, RateLimitEntry>()

/**
 * Check if an IP is rate limited
 * Returns { allowed: boolean, retryAfter?: number }
 */
export function checkRateLimit(ip: string): { allowed: boolean; retryAfter?: number } {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    return { allowed: true }
  }

  // Check if currently blocked
  if (entry.blockedUntil && entry.blockedUntil > now) {
    return {
      allowed: false,
      retryAfter: Math.ceil((entry.blockedUntil - now) / 1000)
    }
  }

  // Block expired or window expired тАФ reset so user gets fresh attempts
  if ((entry.blockedUntil && entry.blockedUntil <= now) || now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.delete(ip)
    return { allowed: true }
  }

  return { allowed: true }
}

/**
 * Record a failed authentication attempt for an IP
 * Returns true if the IP is now blocked
 */
export function recordFailedAuth(ip: string): boolean {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Reset if window has expired
  if (now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Increment attempts
  entry.attempts++
  entry.lastAttempt = now

  // Block if too many attempts
  if (entry.attempts >= RATE_LIMIT_MAX_ATTEMPTS) {
    entry.blockedUntil = now + RATE_LIMIT_BLOCK_DURATION_MS
    return true
  }

  return false
}

/**
 * Clear rate limit for an IP (call on successful auth)
 */
export function clearRateLimit(ip: string): void {
  rateLimitStore.delete(ip)
}

/**
 * Get rate limit status for debugging
 */
export function getRateLimitStatus(ip: string): RateLimitEntry | null {
  return rateLimitStore.get(ip) || null
}

export const authRateLimitConfig = {
  RATE_LIMIT_MAX_ATTEMPTS,
  RATE_LIMIT_WINDOW_MS,
  RATE_LIMIT_BLOCK_DURATION_MS
} as const

/**
 * Kspec IPC Handlers
 *
 * Minimal handlers for operations that need main process access:
 * - Filesystem checks (.kspec/ existence)
 * - Project initialization (runs kspec CLI)
 * - Daemon lifecycle (start/stop)
 *
 * Most kspec operations go directly to the daemon HTTP API from the renderer.
 * These handlers only cover what can't be done from the browser context.
 */

import { ipcMain } from 'electron'
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs'
import { join } from 'path'
import { spawn } from 'child_process'
import { getEnhancedPathWithPortable } from '../platform'

const TASK_INSTRUCTIONS_START = '<!-- TASK_MANAGEMENT_START -->'
const TASK_INSTRUCTIONS_END = '<!-- TASK_MANAGEMENT_END -->'

function getTaskInstructions(backend: 'beads' | 'kspec'): string {
  const beadsCommands = `### CLI Commands (beads)
- \`bd list\` тАФ List tasks (add \`--status=open\` to filter)
- \`bd show <id>\` тАФ Show task details
- \`bd create --title="..." --type=task|bug|feature --priority=2\` тАФ Create a task
- \`bd update <id> --status=in_progress\` тАФ Start a task
- \`bd close <id>\` тАФ Complete a task
- \`bd ready\` тАФ Show tasks ready to work on

### Workflow
1. Check the task panel in the GUI sidebar for available work
2. Click a task to start it, or use the CLI commands above
3. Mark tasks complete from the GUI or CLI when done`

  const kspecInstructions = `@kspec-agents.md

This project uses **kspec** for spec-driven task management and autonomous agent dispatch.
The full agent instructions are in \`kspec-agents.md\` (referenced above).

### Quick Reference
- \`kspec task list\` тАФ List tasks
- \`kspec task create --title "..." --type task|bug|epic|spike|infra --priority 3\` тАФ Create a task
- \`kspec task start <ref>\` тАФ Start a task
- \`kspec inbox add "..."\` тАФ Add idea for later triage
- Use \`/kspec:help\` for full command reference
- Use \`/kspec:writing-specs\` to create spec items (features, requirements, AC)
- Use \`/kspec:plan\` to translate plans into specs and tasks
- Use \`/kspec:triage\` to triage inbox and assess automation eligibility`

  return `${TASK_INSTRUCTIONS_START}
## Task Management

${backend === 'beads' ? beadsCommands : kspecInstructions}
${TASK_INSTRUCTIONS_END}
`
}

export function installTaskInstructions(projectPath: string, backend: 'beads' | 'kspec'): boolean {
  try {
    const claudeDir = join(projectPath, '.claude')
    const claudeMdPath = join(claudeDir, 'CLAUDE.md')

    if (!existsSync(claudeDir)) {
      mkdirSync(claudeDir, { recursive: true })
    }

    let content = ''
    if (existsSync(claudeMdPath)) {
      content = readFileSync(claudeMdPath, 'utf8')
      // Remove existing task section if present
      if (content.includes(TASK_INSTRUCTIONS_START)) {
        const startIdx = content.indexOf(TASK_INSTRUCTIONS_START)
        const endIdx = content.indexOf(TASK_INSTRUCTIONS_END)
        if (startIdx !== -1 && endIdx !== -1) {
          content = content.substring(0, startIdx) + content.substring(endIdx + TASK_INSTRUCTIONS_END.length)
        }
      }
    }

    content += getTaskInstructions(backend)
    writeFileSync(claudeMdPath, content)
    return true
  } catch (e) {
    console.error('Failed to install task instructions:', e)
    return false
  }
}

function getExecOptions() {
  return {
    env: { ...process.env, PATH: getEnhancedPathWithPortable() }
  }
}

function spawnCommand(cmd: string, args: string[], cwd: string): Promise<{ stdout: string; stderr: string; code: number }> {
  return new Promise((resolve) => {
    const proc = spawn(cmd, args, {
      cwd,
      env: getExecOptions().env,
      shell: false
    })

    let stdout = ''
    let stderr = ''

    proc.stdout.on('data', (data) => { stdout += data.toString() })
    proc.stderr.on('data', (data) => { stderr += data.toString() })

    proc.on('close', (code) => {
      resolve({ stdout, stderr, code: code ?? 1 })
    })

    proc.on('error', (err) => {
      resolve({ stdout, stderr: err.message, code: 1 })
    })
  })
}

async function migrateBeadsToKspec(cwd: string): Promise<{ success: boolean; migrated: number; error?: string }> {
  try {
    // 1. Read all beads tasks via bd list --json
    const listResult = await spawnCommand('bd', ['list', '--json'], cwd)
    if (listResult.code !== 0) {
      return { success: false, migrated: 0, error: `Failed to read beads tasks: ${listResult.stderr}` }
    }

    let beadsTasks: Array<Record<string, unknown>> = []
    try {
      const parsed = JSON.parse(listResult.stdout)
      beadsTasks = Array.isArray(parsed) ? parsed : (parsed.issues ?? parsed.tasks ?? [])
    } catch {
      // No tasks to migrate, or empty output тАФ that's fine
      beadsTasks = []
    }

    // 2. Initialize kspec
    const gitDir = join(cwd, '.git')
    if (!existsSync(gitDir)) {
      const gitResult = await spawnCommand('git', ['init'], cwd)
      if (gitResult.code !== 0) {
        return { success: false, migrated: 0, error: `Failed to init git: ${gitResult.stderr}` }
      }
      await spawnCommand('git', ['config', 'user.name', 'kspec'], cwd)
      await spawnCommand('git', ['config', 'user.email', 'kspec@local'], cwd)
      await spawnCommand('git', ['commit', '--allow-empty', '-m', 'init'], cwd)
    }

    const initResult = await spawnCommand('kspec', ['init', '.', '--name', 'Project'], cwd)
    if (initResult.code !== 0) {
      return { success: false, migrated: 0, error: `kspec init failed: ${initResult.stderr}` }
    }

    // Run setup + generate agents instructions
    await spawnCommand('kspec', ['setup'], cwd)
    await spawnCommand('kspec', ['agents', 'generate'], cwd)

    // 3. Ensure daemon is running for task creation
    let daemonReady = false
    const healthCheck = await fetch('http://localhost:3456/api/health').catch(() => null)
    if (healthCheck?.ok) {
      daemonReady = true
    } else {
      const proc = spawn('kspec', ['serve', 'start', '--daemon'], {
        cwd,
        env: getExecOptions().env,
        detached: true,
        stdio: 'ignore'
      })
      proc.unref()
      for (let i = 0; i < 10; i++) {
        await new Promise(r => setTimeout(r, 500))
        const check = await fetch('http://localhost:3456/api/health').catch(() => null)
        if (check?.ok) { daemonReady = true; break }
      }
    }

    // 4. Migrate each task to kspec
    let migrated = 0
    if (daemonReady && beadsTasks.length > 0) {
      // Register project with daemon
      await fetch('http://localhost:3456/api/projects', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ path: cwd })
      }).catch(() => {})

      for (const task of beadsTasks) {
        try {
          // Map beads priority (0-4, 0=critical) to kspec priority (1-5, 1=highest)
          const beadsPriority = typeof task.priority === 'number' ? task.priority : 2
          const kspecPriority = Math.min(5, Math.max(1, beadsPriority + 1))

          // Map beads type to kspec type
          const beadsType = String(task.issue_type ?? task.type ?? 'task')
          const kspecType = beadsType === 'feature' ? 'task' : (['bug', 'task', 'epic'].includes(beadsType) ? beadsType : 'task')

          // Map beads status to kspec status
          const beadsStatus = String(task.status ?? 'open')
          let kspecStatus: string | undefined
          if (beadsStatus === 'in_progress') kspecStatus = 'in_progress'
          else if (beadsStatus === 'closed') kspecStatus = 'completed'
          // 'open' maps to 'pending' which is the default тАФ no need to set

          const res = await fetch('http://localhost:3456/api/tasks', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'X-Kspec-Dir': cwd
            },
            body: JSON.stringify({
              title: String(task.title ?? ''),
              description: task.description ? String(task.description) : undefined,
              priority: kspecPriority,
              type: kspecType,
              status: kspecStatus,
              tags: [`migrated-from:${String(task.id ?? '')}`]
            })
          })
          if (res.ok) migrated++
        } catch {
          // Skip individual task failures
        }
      }
    }

    // 5. Stop beads daemon and remove .beads/ directory
    const beadsDir = join(cwd, '.beads')
    if (existsSync(beadsDir)) {
      // Stop beads daemon first (releases lock files)
      await spawnCommand('bd', ['daemon', '--stop'], cwd).catch(() => {})
      // Small delay for daemon to release files
      await new Promise(r => setTimeout(r, 500))
      const { rmSync } = await import('fs')
      rmSync(beadsDir, { recursive: true, force: true })
    }

    // 6. Update CLAUDE.md to kspec instructions
    installTaskInstructions(cwd, 'kspec')

    return { success: true, migrated }
  } catch (e) {
    return { success: false, migrated: 0, error: String(e) }
  }
}

async function checkAndUpdateKspec(): Promise<void> {
  try {
    const localResult = await spawnCommand('kspec', ['--version'], process.cwd())
    if (localResult.code !== 0) return
    const localVersion = localResult.stdout.trim().replace(/^v/, '')

    const npmResult = await spawnCommand('npm', ['view', '@kynetic-ai/spec', 'version'], process.cwd())
    if (npmResult.code !== 0) return
    const latestVersion = npmResult.stdout.trim()

    if (localVersion !== latestVersion) {
      console.log(`[kspec] Updating from ${localVersion} to ${latestVersion}...`)
      await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec@latest'], process.cwd())
      console.log(`[kspec] Updated to ${latestVersion}`)
    }
  } catch { /* silent */ }
}

export function registerKspecHandlers() {
  // Check if .kspec/ directory exists in a project
  ipcMain.handle('kspec:check', async (_event, cwd: string) => {
    const kspecPath = join(cwd, '.kspec')
    const exists = existsSync(kspecPath)
    return { exists }
  })

  // Initialize kspec in a project directory
  // Requires: git repo, kspec CLI available
  ipcMain.handle('kspec:init', async (_event, cwd: string) => {
    try {
      // Check if it's a git repo first
      const gitDir = join(cwd, '.git')
      if (!existsSync(gitDir)) {
        // Init git first
        const gitResult = await spawnCommand('git', ['init'], cwd)
        if (gitResult.code !== 0) {
          return { success: false, error: `Failed to init git: ${gitResult.stderr}` }
        }
        // Set default git config for the repo
        await spawnCommand('git', ['config', 'user.name', 'kspec'], cwd)
        await spawnCommand('git', ['config', 'user.email', 'kspec@local'], cwd)
        await spawnCommand('git', ['commit', '--allow-empty', '-m', 'init'], cwd)
      }

      // Run kspec init
      const result = await spawnCommand('kspec', ['init', '.', '--name', 'Project'], cwd)
      if (result.code !== 0) {
        return { success: false, error: result.stderr || 'kspec init failed' }
      }

      // Run kspec setup тАФ sets up agent definitions, skills, .agents/ directory
      await spawnCommand('kspec', ['setup'], cwd)

      // Generate kspec-agents.md тАФ full agent instructions with workflows, conventions, skills
      await spawnCommand('kspec', ['agents', 'generate'], cwd)

      // Add task instructions to CLAUDE.md pointing at kspec-agents.md
      installTaskInstructions(cwd, 'kspec')

      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  })

  // Start kspec daemon if not running
  let updateCheckDone = false
  ipcMain.handle('kspec:ensure-daemon', async (_event, cwd: string) => {
    try {
      // Check if daemon is already running
      const res = await fetch('http://localhost:3456/api/health').catch(() => null)
      if (res?.ok) {
        // Register this project with the running daemon
        await fetch('http://localhost:3456/api/projects', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ path: cwd })
        }).catch(() => {})

        // Background update check (once per app session, non-blocking)
        if (!updateCheckDone) {
          updateCheckDone = true
          checkAndUpdateKspec().catch(() => {})
        }

        return { success: true, alreadyRunning: true }
      }

      // Start daemon in background
      const proc = spawn('kspec', ['serve', 'start', '--daemon'], {
        cwd,
        env: getExecOptions().env,
        detached: true,
        stdio: 'ignore'
      })
      proc.unref()

      // Wait for daemon to be ready (up to 5 seconds)
      for (let i = 0; i < 10; i++) {
        await new Promise(r => setTimeout(r, 500))
        const check = await fetch('http://localhost:3456/api/health').catch(() => null)
        if (check?.ok) {
          return { success: true, alreadyRunning: false }
        }
      }

      return { success: false, error: 'Daemon did not start in time' }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  })

  // Check if kspec CLI is installed
  ipcMain.handle('kspec:check-cli', async () => {
    try {
      const result = await spawnCommand('kspec', ['--version'], process.cwd())
      return { installed: result.code === 0, version: result.stdout.trim() }
    } catch {
      return { installed: false }
    }
  })

  // Install kspec CLI via npm
  ipcMain.handle('kspec:install-cli', async () => {
    try {
      const result = await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec'], process.cwd())
      if (result.code !== 0) {
        return { success: false, error: result.stderr || 'npm install failed' }
      }
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  })

  // Migrate beads tasks to kspec (upgrade path)
  ipcMain.handle('kspec:migrate-from-beads', async (_event, cwd: string) => {
    return migrateBeadsToKspec(cwd)
  })

  // Check for kspec updates and install if available
  ipcMain.handle('kspec:update', async () => {
    try {
      // Get installed version
      const localResult = await spawnCommand('kspec', ['--version'], process.cwd())
      if (localResult.code !== 0) return { updated: false, error: 'kspec not installed' }
      const localVersion = localResult.stdout.trim().replace(/^v/, '')

      // Get latest version from npm
      const npmResult = await spawnCommand('npm', ['view', '@kynetic-ai/spec', 'version'], process.cwd())
      if (npmResult.code !== 0) return { updated: false, error: 'Could not check npm' }
      const latestVersion = npmResult.stdout.trim()

      if (localVersion === latestVersion) {
        return { updated: false, current: localVersion, latest: latestVersion }
      }

      // Update
      const updateResult = await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec@latest'], process.cwd())
      if (updateResult.code !== 0) {
        return { updated: false, error: updateResult.stderr || 'Update failed', current: localVersion, latest: latestVersion }
      }

      return { updated: true, previous: localVersion, current: latestVersion }
    } catch (e) {
      return { updated: false, error: String(e) }
    }
  })

  // Start agent dispatch
  ipcMain.handle('kspec:dispatch-start', async (_event, cwd: string) => {
    try {
      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'start'], cwd)
      if (result.code !== 0) {
        return { success: false, error: result.stderr || 'Failed to start dispatch' }
      }
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  })

  // Stop agent dispatch
  ipcMain.handle('kspec:dispatch-stop', async (_event, cwd: string) => {
    try {
      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'stop'], cwd)
      if (result.code !== 0) {
        return { success: false, error: result.stderr || 'Failed to stop dispatch' }
      }
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  })

  // Check agent dispatch status
  ipcMain.handle('kspec:dispatch-status', async (_event, cwd: string) => {
    try {
      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'status', '--json'], cwd)
      if (result.code !== 0) {
        return { running: false }
      }
      try {
        const data = JSON.parse(result.stdout)
        return { running: true, ...data }
      } catch {
        return { running: result.stdout.toLowerCase().includes('running') }
      }
    } catch {
      return { running: false }
    }
  })
}

