197тЖТ
198тЖТ          // Map beads status to kspec status
199тЖТ          const beadsStatus = String(task.status ?? 'open')
200тЖТ          let kspecStatus: string | undefined
201тЖТ          if (beadsStatus === 'in_progress') kspecStatus = 'in_progress'
