   167тЖТ      return { success: false, error: String(e) }
   168тЖТ    }
   169тЖТ  }
   170тЖТ
   171тЖТ  async start(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
   172тЖТ    try {
   173тЖТ      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/start`, cwd)
   174тЖТ      return { success: true }
