   198тЖТ  async update(cwd: string, taskId: string, params: UpdateTaskParams): Promise<{ success: boolean; error?: string }> {
   199тЖТ    try {
   200тЖТ      // Map unified status names back to kspec native status names
   201тЖТ      const body = { ...params }
   202тЖТ      if (body.status === 'open') body.status = 'pending' as TaskStatus
   203тЖТ      if (body.status === 'closed') body.status = 'completed' as TaskStatus
   204тЖТ      await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, body)
   205тЖТ      return { success: true }
   206тЖТ    } catch (e) {
