   211тЖТ  async cycleStatus(cwd: string, taskId: string, currentStatus: TaskStatus): Promise<{ success: boolean; error?: string }> {
   212тЖТ    switch (currentStatus) {
   213тЖТ      case 'open': return this.start(cwd, taskId)
   214тЖТ      case 'in_progress': return this.complete(cwd, taskId)
   215тЖТ      default:
   216тЖТ        // Kspec uses 'pending' internally тАФ 'open' is only the unified status
   217тЖТ        try {
