   228тЖТ  private wsCallbacks: Set<(data: { cwd: string }) => void> = new Set()
   229тЖТ  private watchedCwd: string | null = null
   230тЖТ  private reconnectTimer: ReturnType<typeof setTimeout> | null = null
   231тЖТ  private reconnectDelay = 1000
