   236тЖТ    if (this.ws && this.watchedCwd !== cwd) {
   237тЖТ      this.ws.close()
   238тЖТ      this.ws = null
   239тЖТ    }
   240тЖТ    this.watching = true
   241тЖТ    this.watchedCwd = cwd
