   247тЖТ    if (this.ws) return
   248тЖТ    try {
   249тЖТ      this.ws = new WebSocket(`ws://localhost:${DAEMON_PORT}/ws?project=${encodeURIComponent(cwd)}`)
   250тЖТ      this.ws.onmessage = (event) => {
   251тЖТ        try {
   252тЖТ          const msg = JSON.parse(event.data)
   253тЖТ          if (msg.event === 'tasks:updates' || msg.event === 'task_updated') {
   254тЖТ            this.wsCallbacks.forEach(cb => cb({ cwd }))
   255тЖТ          }
   256тЖТ        } catch { /* ignore parse errors */ }
   257тЖТ      }
   258тЖТ      this.ws.onopen = () => {
