   276тЖТ    this.watching = false
   277тЖТ    this.watchedCwd = null
   278тЖТ    if (this.reconnectTimer) {
   279тЖТ      clearTimeout(this.reconnectTimer)
   280тЖТ      this.reconnectTimer = null
   281тЖТ    }
   282тЖТ    this.ws?.close()
   283тЖТ    this.ws = null
   284тЖТ  }
