    57тЖТ    const retryCount = port - ORCHESTRATOR_PORT
    58тЖТ    if (retryCount >= MAX_PORT_RETRIES) {
    59тЖТ      console.error(`[Orchestrator] Failed to bind after ${MAX_PORT_RETRIES} attempts (ports ${ORCHESTRATOR_PORT}-${port - 1})`)
    60тЖТ      this.server?.close()
    61тЖТ      this.server = null
    62тЖТ      return
    63тЖТ    }
    64тЖТ
    65тЖТ    this.server!.listen(port, '127.0.0.1', () => {
    66тЖТ      this.activePort = port
    67тЖТ      console.log(`[Orchestrator] API server started on port ${port}`)
    68тЖТ    })
    69тЖТ
    70тЖТ    this.server!.once('error', (e: NodeJS.ErrnoException) => {
    71тЖТ      if (e.code === 'EADDRINUSE') {
    72тЖТ        console.warn(`[Orchestrator] Port ${port} in use, trying ${port + 1}`)
    73тЖТ        this.tryListen(port + 1)
    74тЖТ      } else {
    75тЖТ        console.error('[Orchestrator] API server error:', e.message)
    76тЖТ      }
    77тЖТ    })
    78тЖТ  }
    79тЖТ
    80тЖТ  stop(): void {
    81тЖТ    this.server?.close()
    82тЖТ    this.server = null
    83тЖТ  }
    84тЖТ
    85тЖТ  private handleListSessions(res: http.ServerResponse): void {
    86тЖТ    const sessions = this.ptyManager.listSessions()
    87тЖТ    // Enrich with project path from ptyToProject map
    88тЖТ    const enriched = sessions.map(s => ({
    89тЖТ      ...s,
    90тЖТ      projectPath: this.ptyToProject.get(s.id) || s.cwd,
    91тЖТ      projectName: (this.ptyToProject.get(s.id) || s.cwd).split('/').pop() || 'unknown',
    92тЖТ    }))
    93тЖТ    res.writeHead(200)
    94тЖТ    res.end(JSON.stringify({ sessions: enriched }))
    95тЖТ  }
    96тЖТ
    97тЖТ  private handleReadOutput(id: string, maxLines: number, res: http.ServerResponse): void {
    98тЖТ    const lines = this.ptyManager.readOutput(id, maxLines)
    99тЖТ    if (lines === null) {
   100тЖТ      res.writeHead(404)
   101тЖТ      res.end(JSON.stringify({ error: 'Session not found' }))
   102тЖТ      return
   103тЖТ    }
   104тЖТ    res.writeHead(200)
   105тЖТ    res.end(JSON.stringify({ lines }))
   106тЖТ  }
   107тЖТ
   108тЖТ  private handleSendInput(id: string, req: http.IncomingMessage, res: http.ServerResponse): void {
   109тЖТ    let body = ''
   110тЖТ    req.on('data', chunk => {
   111тЖТ      body += chunk
   112тЖТ      if (body.length > 10240) {
   113тЖТ        res.writeHead(413)
   114тЖТ        res.end(JSON.stringify({ error: 'Input too large' }))
   115тЖТ        req.destroy()
   116тЖТ      }
   117тЖТ    })
   118тЖТ    req.on('end', () => {
   119тЖТ      try {
   120тЖТ        const data = JSON.parse(body)
   121тЖТ        const input = data.input || data.text || data.message || ''
   122тЖТ        if (!input) {
   123тЖТ          res.writeHead(400)
   124тЖТ          res.end(JSON.stringify({ error: 'No input provided' }))
   125тЖТ          return
   126тЖТ        }
   127тЖТ
   128тЖТ        const proc = this.ptyManager.getProcess(id)
   129тЖТ        if (!proc) {
   130тЖТ          res.writeHead(404)
