   143тЖТ      console.log('[SessionStore] Main config empty/corrupt, restored from backup (' +
   144тЖТ        backup.workspace.projects.length + ' projects)')
   145тЖТ      // Restore backup as main file atomically (temp + rename)
   146тЖТ      try {
   147тЖТ        const tmpPath = this.configPath + '.tmp'
   148тЖТ        writeFileSync(tmpPath, JSON.stringify(backup, null, 2))
   149тЖТ        renameSync(tmpPath, this.configPath)
   150тЖТ      } catch (e) {
   151тЖТ        console.error('[SessionStore] Failed to restore backup to main:', e)
   152тЖТ      }
   153тЖТ      return backup
   154тЖТ    }
   155тЖТ
