   171тЖТ
   172тЖТ      // Validate we can parse what we're about to write
   173тЖТ      JSON.parse(json)
   174тЖТ
   175тЖТ      // Back up existing file before overwriting (if it has content)
   176тЖТ      if (existsSync(this.configPath)) {
   177тЖТ        try {
   178тЖТ          const stat = statSync(this.configPath)
   179тЖТ          if (stat.size > 0) {
   180тЖТ            // Only update backup if existing file is valid and has projects
   181тЖТ            const existing = this.loadFile(this.configPath)
   182тЖТ            if (existing && (existing.workspace.projects?.length || 0) > 0) {
   183тЖТ              // Atomic backup: write to temp file, then rename
   184тЖТ              const tmpBackup = this.backupPath + '.tmp'
   185тЖТ              writeFileSync(tmpBackup, readFileSync(this.configPath))
   186тЖТ              renameSync(tmpBackup, this.backupPath)
   187тЖТ            }
   188тЖТ          }
   189тЖТ        } catch (e) {
   190тЖТ          console.error('[SessionStore] Failed to update backup:', e)
   191тЖТ        }
   192тЖТ      }
   193тЖТ
   194тЖТ      // Atomic write: write to temp file, then rename
   195тЖТ      const tmpPath = this.configPath + '.tmp'
   196тЖТ      writeFileSync(tmpPath, json)
   197тЖТ
   198тЖТ      try {
   199тЖТ        // Verify the temp file was written completely
   200тЖТ        const written = readFileSync(tmpPath, 'utf-8')
   201тЖТ        JSON.parse(written) // throws if truncated/corrupt
   202тЖТ        renameSync(tmpPath, this.configPath)
   203тЖТ      } catch (verifyErr) {
   204тЖТ        // Clean up temp file on verification or rename failure
   205тЖТ        try { unlinkSync(tmpPath) } catch { /* ignore cleanup errors */ }
   206тЖТ        throw verifyErr
   207тЖТ      }
   208тЖТ    } catch (e) {
   209тЖТ      console.error('[SessionStore] Failed to save workspace:', e)
   210тЖТ    }
   211тЖТ  }
   212тЖТ
   213тЖТ  getWorkspace(): Workspace {
   214тЖТ    return this.data.workspace
   215тЖТ  }
   216тЖТ
   217тЖТ  // Reload workspace from disk (useful when file was modified externally)
   218тЖТ  reloadFromDisk(): void {
   219тЖТ    console.log('[SessionStore] Reloading workspace from disk')
   220тЖТ    this.data = this.load()
   221тЖТ    console.log('[SessionStore] Reloaded, projects:', this.data.workspace?.projects?.length || 0)
   222тЖТ  }
   223тЖТ
   224тЖТ  saveWorkspace(workspace: Workspace): void {
   225тЖТ    // Protect against overwriting populated workspace with empty one
   226тЖТ    const incomingProjects = workspace?.projects?.length || 0
   227тЖТ    const currentProjects = this.data.workspace?.projects?.length || 0
   228тЖТ    if (incomingProjects === 0 && currentProjects > 0) {
   229тЖТ      console.log('[SessionStore] Rejected empty workspace save - current has', currentProjects, 'projects')
   230тЖТ      return
   231тЖТ    }
   232тЖТ    this.data.workspace = workspace
   233тЖТ    this.save()
   234тЖТ    syncMetaProjects(workspace)
   235тЖТ  }
   236тЖТ
